/* ── Related Posts Section ── */

.rp-section {
    margin-top: 0;
    padding-top: 1rem;
    border-top: 1px solid var(--border-light);
    padding-bottom: 5rem;
    max-width: 620px;
    width: 100%;
    padding-left: 24px;
    padding-right: 24px;
    box-sizing: border-box;
}

.rp-heading {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 0.06rem;
    text-transform: uppercase;
    background: linear-gradient(135deg, var(--accent-amber), var(--accent-purple));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin: 0 0 1rem 0;
}

.rp-heading-icon {
    width: 15px;
    height: 15px;
    flex-shrink: 0;
    color: var(--accent-amber);
    filter: drop-shadow(0 0 3px rgba(212, 168, 83, 0.35));
    animation: rp-icon-pulse 3s ease-in-out infinite;
}

@keyframes rp-icon-pulse {
    0%, 100% { opacity: 0.8; transform: scale(1); }
    50% { opacity: 1; transform: scale(1.1); }
}

.rp-heading::after {
    content: '';
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, var(--accent-amber), transparent);
    opacity: 0.3;
}

